import { Injectable, Logger } from '@nestjs/common';
import * as nodemailer from 'nodemailer';

export interface EmailOptions {
  to: string;
  subject: string;
  html: string;
  text?: string;
}

@Injectable()
export class EmailService {
  private readonly logger = new Logger(EmailService.name);
  private transporter: nodemailer.Transporter;

  constructor() {
    this.initializeTransporter();
  }

  private initializeTransporter() {
    const emailConfig = {
      host: process.env.SMTP_HOST || 'smtp.gmail.com',
      port: parseInt(process.env.SMTP_PORT || '587'),
      secure: process.env.SMTP_SECURE === 'true',
      auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASS,
      },
    };

    if (!emailConfig.auth.user || !emailConfig.auth.pass) {
      this.logger.warn('Email service not configured. Set SMTP_USER and SMTP_PASS in .env');
      return;
    }

    this.transporter = nodemailer.createTransport(emailConfig);
    this.logger.log('Email service initialized');
  }

  async sendEmail(options: EmailOptions): Promise<boolean> {
    if (!this.transporter) {
      this.logger.warn('Email service not configured, skipping email');
      return false;
    }

    try {
      const info = await this.transporter.sendMail({
        from: `"VulnX Hunter" <${process.env.SMTP_USER}>`,
        to: options.to,
        subject: options.subject,
        text: options.text,
        html: options.html,
      });

      this.logger.log(`Email sent: ${info.messageId}`);
      return true;
    } catch (error) {
      this.logger.error(`Failed to send email: ${error.message}`);
      return false;
    }
  }

  async sendScanCompleteNotification(
    userEmail: string,
    targetName: string,
    scanId: string,
    vulnerabilityCount: number,
  ) {
    const subject = `🎯 Scan Complete: ${targetName}`;
    const html = `
      <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
        <h2 style="color: #00FFB2;">VulnX Hunter - Scan Complete</h2>
        <p>Your security scan has completed successfully.</p>

        <div style="background: #1a1a1a; padding: 20px; border-radius: 8px; margin: 20px 0;">
          <h3 style="color: #00FFB2; margin-top: 0;">Scan Results</h3>
          <p style="color: #fff;"><strong>Target:</strong> ${targetName}</p>
          <p style="color: #fff;"><strong>Scan ID:</strong> ${scanId}</p>
          <p style="color: #fff;"><strong>Vulnerabilities Found:</strong> ${vulnerabilityCount}</p>
        </div>

        <p>
          <a href="${process.env.FRONTEND_URL}/dashboard" 
             style="background: #00FFB2; color: #000; padding: 12px 24px; text-decoration: none; border-radius: 4px; display: inline-block;">
            View Results
          </a>
        </p>

        <p style="color: #666; font-size: 12px; margin-top: 30px;">
          This is an automated message from VulnX Hunter. Do not reply to this email.
        </p>
      </div>
    `;

    return this.sendEmail({
      to: userEmail,
      subject,
      html,
      text: `Scan complete for ${targetName}. Found ${vulnerabilityCount} vulnerabilities. Scan ID: ${scanId}`,
    });
  }

  async sendVulnerabilityAlert(
    userEmail: string,
    vulnerability: {
      title: string;
      severity: string;
      targetName: string;
      cvssScore: number;
    },
  ) {
    const severityColor = {
      CRITICAL: '#FF0000',
      HIGH: '#FF6B00',
      MEDIUM: '#FFB800',
      LOW: '#00B8FF',
      INFORMATIONAL: '#808080',
    };

    const subject = `🚨 ${vulnerability.severity} Vulnerability Detected: ${vulnerability.title}`;
    const html = `
      <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
        <h2 style="color: ${severityColor[vulnerability.severity]};">⚠️ New Vulnerability Detected</h2>

        <div style="background: #1a1a1a; padding: 20px; border-radius: 8px; margin: 20px 0; border-left: 4px solid ${severityColor[vulnerability.severity]};">
          <h3 style="color: #fff; margin-top: 0;">${vulnerability.title}</h3>
          <p style="color: #fff;"><strong>Target:</strong> ${vulnerability.targetName}</p>
          <p style="color: #fff;"><strong>Severity:</strong> <span style="color: ${severityColor[vulnerability.severity]};">${vulnerability.severity}</span></p>
          <p style="color: #fff;"><strong>CVSS Score:</strong> ${vulnerability.cvssScore}</p>
        </div>

        <p>
          <a href="${process.env.FRONTEND_URL}/vulnerability" 
             style="background: #FF0000; color: #fff; padding: 12px 24px; text-decoration: none; border-radius: 4px; display: inline-block;">
            View Details
          </a>
        </p>
      </div>
    `;

    return this.sendEmail({
      to: userEmail,
      subject,
      html,
      text: `${vulnerability.severity} vulnerability detected: ${vulnerability.title} on ${vulnerability.targetName}`,
    });
  }

  async sendWeeklyReport(
    userEmail: string,
    stats: {
      totalScans: number;
      newVulnerabilities: number;
      criticalCount: number;
      highCount: number;
    },
  ) {
    const subject = `📊 Weekly Security Report`;
    const html = `
      <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
        <h2 style="color: #00FFB2;">VulnX Hunter - Weekly Report</h2>
        <p>Here's your security summary for the past week.</p>

        <div style="background: #1a1a1a; padding: 20px; border-radius: 8px; margin: 20px 0;">
          <h3 style="color: #00FFB2; margin-top: 0;">Activity Summary</h3>
          <p style="color: #fff;"><strong>Total Scans:</strong> ${stats.totalScans}</p>
          <p style="color: #fff;"><strong>New Vulnerabilities:</strong> ${stats.newVulnerabilities}</p>
          <p style="color: #FF0000;"><strong>Critical:</strong> ${stats.criticalCount}</p>
          <p style="color: #FF6B00;"><strong>High:</strong> ${stats.highCount}</p>
        </div>

        <p>
          <a href="${process.env.FRONTEND_URL}/reports" 
             style="background: #00FFB2; color: #000; padding: 12px 24px; text-decoration: none; border-radius: 4px; display: inline-block;">
            View Full Report
          </a>
        </p>
      </div>
    `;

    return this.sendEmail({
      to: userEmail,
      subject,
      html,
      text: `Weekly report: ${stats.totalScans} scans, ${stats.newVulnerabilities} new vulnerabilities`,
    });
  }
}

